class SecureDataValidator:
    """Validates and sanitizes uploaded data"""
    
    ALLOWED_EXTENSIONS = {'.csv', '.jpg', '.jpeg', '.png'}
    MAX_FILE_SIZE = 10 * 1024 * 1024  # 10MB
    MAX_IMAGE_DIMENSION = 4096
    MAX_CSV_ROWS = 100000
    
    @staticmethod
    def validate_file_extension(filename: str) -> bool:
        """Validate file extension"""
        ext = Path(filename).suffix.lower()
        return ext in SecureDataValidator.ALLOWED_EXTENSIONS
    
    @staticmethod
    def validate_file_size(file_size: int) -> bool:
        """Validate file size"""
        return 0 < file_size <= SecureDataValidator.MAX_FILE_SIZE
    
    @staticmethod
    def sanitize_filename(filename: str) -> str:
        """Sanitize filename to prevent path traversal"""
        filename = os.path.basename(filename)
        filename = "".join(c for c in filename if c.isalnum() or c in ('_', '-', '.'))
        return filename[:255]
    
    @staticmethod
    def validate_image(image_data: bytes) -> Optional[Image.Image]:
        """Validate and load image safely"""
        try:
            img = Image.open(io.BytesIO(image_data))
            
            if img.width > SecureDataValidator.MAX_IMAGE_DIMENSION or \
               img.height > SecureDataValidator.MAX_IMAGE_DIMENSION:
                logger.warning(f"Image dimensions too large: {img.width}x{img.height}")
                return None
            
            if img.mode not in ('RGB', 'L', 'RGBA'):
                img = img.convert('RGB')
            
            img.verify()
            img = Image.open(io.BytesIO(image_data))
            
            return img
        except Exception as e:
            logger.error(f"Image validation failed: {e}")
            return None
    
    @staticmethod
    def validate_csv(csv_data: bytes) -> Optional[pd.DataFrame]:
        """Validate and load CSV safely"""
        try:
            df = pd.read_csv(
                io.BytesIO(csv_data),
                nrows=SecureDataValidator.MAX_CSV_ROWS,
                engine='python',
                on_bad_lines='skip'
            )
            
            if df.empty:
                logger.warning("CSV file is empty")
                return None
            
            for col in df.columns:
                if df[col].dtype == 'object':
                    df[col] = df[col].astype(str).str[:1000]
            
            return df
        except Exception as e:
            logger.error(f"CSV validation failed: {e}")
            return None


class SecureStorageManager:
    """Manages secure storage of uploaded data"""
    
    def __init__(self, base_path: str = "./secure_data"):
        self.base_path = Path(base_path)
        self.base_path.mkdir(parents=True, exist_ok=True)
        
        self.images_path = self.base_path / "images"
        self.csv_path = self.base_path / "csv"
        self.models_path = self.base_path / "models"
        
        for path in [self.images_path, self.csv_path, self.models_path]:
            path.mkdir(parents=True, exist_ok=True)
            os.chmod(path, 0o700)
    
    def generate_secure_filename(self, original_filename: str) -> str:
        """Generate secure unique filename"""
        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        random_suffix = secrets.token_hex(8)
        ext = Path(original_filename).suffix.lower()
        return f"{timestamp}_{random_suffix}{ext}"
    
    def save_image(self, image: Image.Image, original_filename: str, label: str) -> str:
        """Save image securely"""
        label_path = self.images_path / self.sanitize_label(label)
        label_path.mkdir(parents=True, exist_ok=True)
        
        secure_filename = self.generate_secure_filename(original_filename)
        file_path = label_path / secure_filename
        
        image.save(file_path, format='PNG')
        os.chmod(file_path, 0o600)
        
        return str(file_path)
    
    def save_csv(self, df: pd.DataFrame, original_filename: str) -> str:
        """Save CSV securely"""
        secure_filename = self.generate_secure_filename(original_filename)
        file_path = self.csv_path / secure_filename
        
        df.to_csv(file_path, index=False)
        os.chmod(file_path, 0o600)
        
        return str(file_path)
    
    @staticmethod
    def sanitize_label(label: str) -> str:
        """Sanitize label name"""
        label = "".join(c for c in label if c.isalnum() or c in ('_', '-'))
        return label[:50].lower()


class SecureImageClassificationPipeline:
    """Secure ML training pipeline for image classification"""
    
    def __init__(self, storage_manager: SecureStorageManager, num_classes: int = 10):
        self.storage = storage_manager
        self.num_classes = num_classes
        self.model = None
        self.class_names = []
        self.img_height = 224
        self.img_width = 224
        self.batch_size = 32
        
    def create_model(self) -> keras.Model:
        """Create a secure CNN model with input validation"""
        model = keras.Sequential([
            layers.InputLayer(input_shape=(self.img_height, self.img_width, 3)),
            layers.Rescaling(1./255),
            
            layers.Conv2D(32, 3, activation='relu', padding='same'),
            layers.MaxPooling2D(),
            layers.Dropout(0.2),
            
            layers.Conv2D(64, 3, activation='relu', padding='same'),
            layers.MaxPooling2D(),
            layers.Dropout(0.2),
            
            layers.Conv2D(128, 3, activation='relu', padding='same'),
            layers.MaxPooling2D(),
            layers.Dropout(0.3),
            
            layers.Flatten(),
            layers.Dense(256, activation='relu'),
            layers.Dropout(0.5),
            layers.Dense(self.num_classes, activation='softmax')
        ])
        
        model.compile(
            optimizer='adam',
            loss='sparse_categorical_crossentropy',
            metrics=['accuracy']
        )
        
        return model
    
    def load_dataset_from_directory(self, validation_split: float = 0.2) -> Tuple[tf.data.Dataset, tf.data.Dataset]:
        """Load dataset from directory with validation"""
        try:
            train_ds = tf.keras.utils.image_dataset_from_directory(
                self.storage.images_path,
                validation_split=validation_split,
                subset="training",
                seed=123,
                image_size=(self.img_height, self.img_width),
                batch_size=self.batch_size,
                label_mode='int'
            )
            
            val_ds = tf.keras.utils.image_dataset_from_directory(
                self.storage.images_path,
                validation_split=validation_split,
                subset="validation",
                seed=123,
                image_size=(self.img_height, self.img_width),
                batch_size=self.batch_size,
                label_mode='int'
            )
            
            self.class_names = train_ds.class_names
            
            AUTOTUNE = tf.data.AUTOTUNE
            train_ds = train_ds.cache().prefetch(buffer_size=AUTOTUNE)
            val_ds = val_ds.cache().prefetch(buffer_size=AUTOTUNE)
            
            return train_ds, val_ds
        except Exception as e:
            logger.error(f"Failed to load dataset: {e}")
            raise
    
    def train_model(self, epochs: int = 10, validation_split: float = 0.2) -> dict:
        """Train model with security measures"""
        if epochs > 100:
            logger.warning("Limiting epochs to 100 for security")
            epochs = 100
        
        try:
            train_ds, val_ds = self.load_dataset_from_directory(validation_split)
            
            self.num_classes = len(self.class_names)
            self.model = self.create_model()
            
            early_stopping = keras.callbacks.EarlyStopping(
                monitor='val_loss',
                patience=5,
                restore_best_weights=True
            )
            
            reduce_lr = keras.callbacks.ReduceLROnPlateau(
                monitor='val_loss',
                factor=0.5,
                patience=3,
                min_lr=1e-7
            )
            
            history = self.model.fit(
                train_ds,
                validation_data=val_ds,
                epochs=epochs,
                callbacks=[early_stopping, reduce_lr],
                verbose=1
            )
            
            return {
                'status': 'success',
                'epochs_trained': len(history.history['loss']),
                'final_accuracy': float(history.history['accuracy'][-1]),
                'final_val_accuracy': float(history.history['val_accuracy'][-1]),
                'class_names': self.class_names
            }
        except Exception as e:
            logger.error(f"Training failed: {e}")
            return {'status': 'error', 'message': str(e)}
    
    def save_model(self, model_name: str = "model") -> str:
        """Save trained model securely"""
        if self.model is None:
            raise ValueError("No model to save")
        
        model_name = SecureDataValidator.sanitize_filename(model_name)
        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        model_path = self.storage.models_path / f"{model_name}_{timestamp}"
        
        self.model.save(model_path)
        
        metadata = {
            'class_names': self.class_names,
            'num_classes': self.num_classes,
            'img_height': self.img_height,
            'img_width': self.img_width,
            'timestamp': timestamp
        }
        
        metadata_path = model_path / "metadata.json"
        with open(metadata_path, 'w') as f:
            json.dump(metadata, f)
        
        return str(model_path)
    
    def load_model(self, model_path: str) -> bool:
        """Load trained model securely"""
        try:
            model_path = Path(model_path)
            if not model_path.exists() or not model_path.is_dir():
                logger.error(f"Model path does not exist: {model_path}")
                return False
            
            if not str(model_path.resolve()).startswith(str(self.storage.models_path.resolve())):
                logger.error("Path traversal attempt detected")
                return False
            
            self.model = keras.models.load_model(model_path)
            
            metadata_path = model_path / "metadata.json"
            if metadata_path.exists():
                with open(metadata_path, 'r') as f:
                    metadata = json.load(f)
                    self.class_names = metadata.get('class_names', [])
                    self.num_classes = metadata.get('num_classes', 10)
            
            return True
        except Exception as e:
            logger.error(f"Failed to load model: {e}")
            return False


class SecureTrainingAPI:
    """Secure API for handling training data uploads"""
    
    def __init__(self, storage_path: str = "./secure_data"):
        self.validator = SecureDataValidator()
        self.storage = SecureStorageManager(storage_path)
        self.pipeline = SecureImageClassificationPipeline(self.storage)
        self.upload_log = []
    
    def upload_image(self, image_data: bytes, filename: str, label: str) -> dict:
        """Handle image upload with validation"""
        try:
            if not self.validator.validate_file_extension(filename):
                return {'status': 'error', 'message': 'Invalid file extension'}
            
            if not self.validator.validate_file_size(len(image_data)):
                return {'status': 'error', 'message': 'File size exceeds limit'}
            
            sanitized_filename = self.validator.sanitize_filename(filename)
            
            img = self.validator.validate_image(image_data)
            if img is None:
                return {'status': 'error', 'message': 'Invalid image file'}
            
            if not label or len(label) > 50:
                return {'status': 'error', 'message': 'Invalid label'}
            
            saved_path = self.storage.save_image(img, sanitized_filename, label)
            
            log_entry = {
                'timestamp': datetime.now().isoformat(),
                'type': 'image',
                'filename': sanitized_filename,
                'label': label,
                'size': len(image_data)
            }
            self.upload_log.append(log_entry)
            
            return {
                'status': 'success',
                'message': 'Image uploaded successfully',
                'path': saved_path
            }
        except Exception as e:
            logger.error(f"Image upload failed: {e}")
            return {'status': 'error', 'message': 'Upload failed'}
    
    def upload_csv(self, csv_data: bytes, filename: str) -> dict:
        """Handle CSV upload with validation"""
        try:
            if not self.validator.validate_file_extension(filename):
                return {'status': 'error', 'message': 'Invalid file extension'}
            
            if not self.validator.validate_file_size(len(csv_data)):
                return {'status': 'error', 'message': 'File size exceeds limit'}
            
            sanitized_filename = self.validator.sanitize_filename(filename)
            
            df = self.validator.validate_csv(csv_data)
            if df is None:
                return {'status': 'error', 'message': 'Invalid CSV file'}
            
            saved_path = self.storage.save_csv(df, sanitized_filename)
            
            log_entry = {
                'timestamp': datetime.now().isoformat(),
                'type': 'csv',
                'filename': sanitized_filename,
                'rows': len(df),
                'columns': len(df.columns)
            }
            self.upload_log.append(log_entry)
            
            return {
                'status': 'success',
                'message': 'CSV uploaded successfully',
                'path': saved_path,
                'rows': len(df),
                'columns': list(df.columns)
            }
        except Exception as e:
            logger.error(f"CSV upload failed: {e}")
            return {'status': 'error', 'message': 'Upload failed'}
    
    def train_model(self, epochs: int = 10) -> dict:
        """Train model on uploaded data"""
        try:
            if epochs < 1 or epochs > 100:
                return {'status': 'error', 'message': 'Invalid epochs value'}
            
            result = self.pipeline.train_model(epochs=epochs)
            
            if result['status'] == 'success':
                model_path = self.pipeline.save_model()
                result['model_path'] = model_path
            
            return result
        except Exception as e:
            logger.error(f"Training failed: {e}")
            return {'status': 'error', 'message': 'Training failed'}
    
    def get_upload_statistics(self) -> dict:
        """Get statistics about uploaded data"""
        return {
            'total_uploads': len(self.upload_log),
            'recent_uploads': self.upload_log[-10:] if self.upload_log else []
        }


